deployment.program:
program veilsub_governance_v2.aleo;

struct BallotReceipt:
    proposal_id as field;
    commitment as field;
    nullifier as field;

struct ProposalReceipt:
    proposal_id as field;
    description_hash as field;
    creator_hash as field;

mapping proposals:
    key as field.public;
    value as u8.public;

mapping proposal_creator:
    key as field.public;
    value as field.public;

mapping proposal_description:
    key as field.public;
    value as field.public;

mapping yes_commit:
    key as field.public;
    value as group.public;

mapping no_commit:
    key as field.public;
    value as group.public;

mapping yes_blind_sum:
    key as field.public;
    value as scalar.public;

mapping no_blind_sum:
    key as field.public;
    value as scalar.public;

mapping vote_count:
    key as field.public;
    value as u64.public;

mapping ballot_nullifier:
    key as field.public;
    value as boolean.public;

mapping resolved_yes:
    key as field.public;
    value as u64.public;

mapping resolved_no:
    key as field.public;
    value as u64.public;

mapping creator_proposal_count:
    key as field.public;
    value as u64.public;

mapping total_proposals:
    key as u8.public;
    value as u64.public;

mapping total_ballots:
    key as u8.public;
    value as u64.public;

function create_proposal:
    input r0 as field.private;
    input r1 as field.private;
    hash.psd2 self.caller into r2 as field;
    cast r0 r1 r2 into r3 as ProposalReceipt;
    async create_proposal r0 r2 r1 into r4;
    output r3 as ProposalReceipt.private;
    output r4 as veilsub_governance_v2.aleo/create_proposal.future;

finalize create_proposal:
    input r0 as field.public;
    input r1 as field.public;
    input r2 as field.public;
    contains proposals[r0] into r3;
    not r3 into r4;
    assert.eq r4 true;
    get.or_use creator_proposal_count[r1] 0u64 into r5;
    lt r5 50u64 into r6;
    assert.eq r6 true;
    set 0u8 into proposals[r0];
    set r1 into proposal_creator[r0];
    set r2 into proposal_description[r0];
    set 0group into yes_commit[r0];
    set 0group into no_commit[r0];
    set 0scalar into yes_blind_sum[r0];
    set 0scalar into no_blind_sum[r0];
    set 0u64 into vote_count[r0];
    add r5 1u64 into r7;
    set r7 into creator_proposal_count[r1];
    get.or_use total_proposals[0u8] 0u64 into r8;
    add r8 1u64 into r9;
    set r9 into total_proposals[0u8];

function cast_ballot:
    input r0 as field.private;
    input r1 as boolean.private;
    input r2 as field.private;
    hash.psd2 self.caller into r3 as field;
    add r3 r0 into r4;
    add r4 9999999999999999999field into r5;
    hash.bhp256 r5 into r6 as field;
    ternary r1 1field 0field into r7;
    add r7 r0 into r8;
    add r8 r3 into r9;
    add r9 r2 into r10;
    hash.psd2 r10 into r11 as field;
    hash.bhp256 r2 into r12 as scalar;
    commit.bhp256 r11 r12 into r13 as field;
    add r2 9999999999999999999field into r14;
    hash.bhp256 r14 into r15 as scalar;
    mul r15 4756945026257194583189722752066097511643190336079386933095348702435126773568group into r16;
    add 1540945439182663264862696551825005342995406165131907382295858612069623286213group r16 into r17;
    ternary r1 r17 0group into r18;
    ternary r1 0group r17 into r19;
    ternary r1 r15 0scalar into r20;
    ternary r1 0scalar r15 into r21;
    cast r0 r13 r6 into r22 as BallotReceipt;
    async cast_ballot r0 r6 r18 r19 r20 r21 into r23;
    output r22 as BallotReceipt.private;
    output r23 as veilsub_governance_v2.aleo/cast_ballot.future;

finalize cast_ballot:
    input r0 as field.public;
    input r1 as field.public;
    input r2 as group.public;
    input r3 as group.public;
    input r4 as scalar.public;
    input r5 as scalar.public;
    get proposals[r0] into r6;
    assert.eq r6 0u8;
    get.or_use ballot_nullifier[r1] false into r7;
    not r7 into r8;
    assert.eq r8 true;
    set true into ballot_nullifier[r1];
    get.or_use yes_commit[r0] 0group into r9;
    add r9 r2 into r10;
    set r10 into yes_commit[r0];
    get.or_use no_commit[r0] 0group into r11;
    add r11 r3 into r12;
    set r12 into no_commit[r0];
    get.or_use yes_blind_sum[r0] 0scalar into r13;
    add r13 r4 into r14;
    set r14 into yes_blind_sum[r0];
    get.or_use no_blind_sum[r0] 0scalar into r15;
    add r15 r5 into r16;
    set r16 into no_blind_sum[r0];
    get.or_use vote_count[r0] 0u64 into r17;
    add r17 1u64 into r18;
    set r18 into vote_count[r0];
    get.or_use total_ballots[0u8] 0u64 into r19;
    add r19 1u64 into r20;
    set r20 into total_ballots[0u8];

function resolve_proposal:
    input r0 as field.private;
    input r1 as u64.public;
    input r2 as u64.public;
    async resolve_proposal r0 r1 r2 into r3;
    output r3 as veilsub_governance_v2.aleo/resolve_proposal.future;

finalize resolve_proposal:
    input r0 as field.public;
    input r1 as u64.public;
    input r2 as u64.public;
    get proposals[r0] into r3;
    assert.eq r3 0u8;
    get.or_use vote_count[r0] 0u64 into r4;
    gte r4 1u64 into r5;
    assert.eq r5 true;
    add r1 r2 into r6;
    assert.eq r6 r4;
    get.or_use yes_commit[r0] 0group into r7;
    get.or_use yes_blind_sum[r0] 0scalar into r8;
    cast r1 into r9 as scalar;
    mul r9 1540945439182663264862696551825005342995406165131907382295858612069623286213group into r10;
    mul r8 4756945026257194583189722752066097511643190336079386933095348702435126773568group into r11;
    add r10 r11 into r12;
    assert.eq r7 r12;
    get.or_use no_commit[r0] 0group into r13;
    get.or_use no_blind_sum[r0] 0scalar into r14;
    cast r2 into r15 as scalar;
    mul r15 1540945439182663264862696551825005342995406165131907382295858612069623286213group into r16;
    mul r14 4756945026257194583189722752066097511643190336079386933095348702435126773568group into r17;
    add r16 r17 into r18;
    assert.eq r13 r18;
    set 1u8 into proposals[r0];
    set r1 into resolved_yes[r0];
    set r2 into resolved_no[r0];

function cancel_proposal:
    input r0 as field.private;
    hash.psd2 self.caller into r1 as field;
    async cancel_proposal r0 r1 into r2;
    output r2 as veilsub_governance_v2.aleo/cancel_proposal.future;

finalize cancel_proposal:
    input r0 as field.public;
    input r1 as field.public;
    get proposals[r0] into r2;
    assert.eq r2 0u8;
    get proposal_creator[r0] into r3;
    assert.eq r1 r3;
    set 2u8 into proposals[r0];

function verify_tally:
    input r0 as field.private;
    input r1 as u64.public;
    input r2 as u64.public;
    async verify_tally r0 r1 r2 into r3;
    output r3 as veilsub_governance_v2.aleo/verify_tally.future;

finalize verify_tally:
    input r0 as field.public;
    input r1 as u64.public;
    input r2 as u64.public;
    get proposals[r0] into r3;
    assert.eq r3 1u8;
    get resolved_yes[r0] into r4;
    get resolved_no[r0] into r5;
    assert.eq r1 r4;
    assert.eq r2 r5;
    get.or_use yes_commit[r0] 0group into r6;
    get.or_use yes_blind_sum[r0] 0scalar into r7;
    cast r1 into r8 as scalar;
    mul r8 1540945439182663264862696551825005342995406165131907382295858612069623286213group into r9;
    mul r7 4756945026257194583189722752066097511643190336079386933095348702435126773568group into r10;
    add r9 r10 into r11;
    assert.eq r6 r11;
    get.or_use no_commit[r0] 0group into r12;
    get.or_use no_blind_sum[r0] 0scalar into r13;
    cast r2 into r14 as scalar;
    mul r14 1540945439182663264862696551825005342995406165131907382295858612069623286213group into r15;
    mul r13 4756945026257194583189722752066097511643190336079386933095348702435126773568group into r16;
    add r15 r16 into r17;
    assert.eq r12 r17;

constructor:
    assert.eq edition 0u16;
